@Service
public class MfaService {
    private final UserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;

    public MfaService(UserRepository userRepository, 
                      BackupCodeRepository backupCodeRepository,
                      PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    public void enableMfa(Long userId) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new RuntimeException("User not found"));

        if (user.isMfaEnabled()) {
            throw new RuntimeException("MFA already enabled");
        }

        generateBackupCodes(user);
        user.setMfaEnabled(true);
        userRepository.save(user);
    }

    private void generateBackupCodes(User user) {
        List<BackupCode> codes = new ArrayList<>();
        for (int i = 0; i < 10; i++) {
            String code = generateRandomCode();
            String hashedCode = passwordEncoder.encode(code);
            BackupCode backupCode = new BackupCode();
            backupCode.setUser(user);
            backupCode.setCodeHash(hashedCode);
            codes.add(backupCode);
        }
        backupCodeRepository.saveAll(codes);
    }

    private String generateRandomCode() {
        Random random = new Random();
        StringBuilder code = new StringBuilder();
        for (int i = 0; i < 8; i++) {
            code.append(random.nextInt(10));
        }
        return code.toString();
    }

    public boolean validateBackupCode(Long userId, String code) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new RuntimeException("User not found"));

        String hashedCode = passwordEncoder.encode(code);
        Optional<BackupCode> backupCode = backupCodeRepository.findByCodeHashAndUsedFalse(hashedCode);

        if (backupCode.isPresent()) {
            BackupCode bc = backupCode.get();
            if (bc.getUser().getId().equals(userId)) {
                bc.setUsed(true);
                backupCodeRepository.save(bc);
                return true;
            }
        }
        return false;
    }

    public List<String> getAvailableBackupCodes(Long userId) {
        List<BackupCode> codes = backupCodeRepository.findByUserIdAndUsedFalse(userId);
        return codes.stream()
                .map(bc -> "Code: " + bc.getCodeHash().substring(0, 4) + "****")
                .collect(ArrayList::new, ArrayList::add, ArrayList::addAll);
    }
}

@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    private final MfaService mfaService;

    public MfaController(MfaService mfaService) {
        this.mfaService = mfaService;
    }

    @PostMapping("/enable")
    public ResponseEntity<?> enableMfa(@RequestParam Long userId) {
        try {
            mfaService.enableMfa(userId);
            return ResponseEntity.ok().body("MFA enabled successfully");
        } catch (Exception e) {
            return ResponseEntity.badRequest().body("Failed to enable MFA: " + e.getMessage());
        }
    }

    @PostMapping("/authenticate")
    public ResponseEntity<?> authenticateWithBackupCode(@RequestParam Long userId,
                                                       @RequestParam String code) {
        try {
            boolean valid = mfaService.validateBackupCode(userId, code);
            if (valid) {
                return ResponseEntity.ok().body("Authentication successful with backup code");
            } else {
                return ResponseEntity.badRequest().body("Invalid backup code");
            }
        } catch (Exception e) {
            return ResponseEntity.badRequest().body("Authentication failed: " + e.getMessage());
        }
    }

    @GetMapping("/codes")
    public ResponseEntity<?> getBackupCodes(@RequestParam Long userId) {
        try {
            List<String> codes = mfaService.getAvailableBackupCodes(userId);
            return ResponseEntity.ok().body(codes);
        } catch (Exception e) {
            return ResponseEntity.badRequest().body("Failed to retrieve backup codes: " + e.getMessage());
        }
    }
}